import { NextRequest, NextResponse } from "next/server"
import { connectDB } from "@/lib/db"
import Document from "@/models/Document"
import path from "path"
import fs from "fs"

export async function POST(req: NextRequest) {
  try {
    await connectDB()

    const { templateId, propertyId } = await req.json()

    // 👉 TEMP: just create dummy file
    const fileName = `doc-${Date.now()}.txt`
    const filePath = path.join(process.cwd(), "public", "generated", fileName)

    fs.writeFileSync(filePath, "Generated Document")

    // 👉 version logic
    const count = await Document.countDocuments({ templateId, propertyId })

    const doc = await Document.create({
      templateId,
      propertyId,
      fileUrl: `/generated/${fileName}`,
      version: count + 1,
    })

    return NextResponse.json(doc)
  } catch (err) {
    return NextResponse.json({ error: "Generation failed" }, { status: 500 })
  }
}